const questionRaw = $input.first().json.body.question || "";
const question = questionRaw.toLowerCase().trim();

// ======= ⚙️ Hàm bỏ dấu tiếng Việt =======
function removeDiacritics(str) {
  return str
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .replace(/đ/g, "d")
    .replace(/Đ/g, "D");
}

// Bỏ dấu cho input để check so khớp
const questionNormalized = removeDiacritics(question);

// ======= 🧠 Danh sách từ khóa liên quan Tarot =======
const keywords = [
  "tinh cam","moi quan he","hop nhau","loi khuyen","nen lam gi","nghi gi ve",
  "tim hieu","de y den","an tuong","xuat hien","quay lai","nguoi thu ba",
  "qua khu","tuong lai","sap toi","ngoai tinh","gia dinh","lua doi","mqh",
  "suc khoe","cong viec","du hoc","vuot qua","nguoi yeu cu","crush","yeu minh",
  "thich minh","co ai khac","dinh menh","duyen phan","co hoi","thanh cong",
  "doi viec","thi cu","dinh huong","muc tieu","so phan","vu tru","stress",
  "chua lanh","thang tien","tai chinh","phong van","kinh doanh","may man",
  "vo","chong"
];

// ======= 🚫 Từ nhạy cảm / bị chặn =======
const banned = [
  "chet","tu tu","giet","ma","bua","yem","ngai","phap su","hai nguoi","danh de","trung so"
];

// ======= 🧩 Kiểm tra nhanh =======
const tooShort = questionNormalized.length < 15;
const hasBanned = banned.some(b => questionNormalized.includes(b));
const hasKeyword = keywords.some(k => questionNormalized.includes(k));

// ======= 🧠 Logic quyết định =======
let isTarot = false;

if (!tooShort && !hasBanned && hasKeyword) {
  isTarot = true;
}

// ======= 🔚 Output cực gọn =======
return [{ isTarot }];

for (const item of $input.all()) {
  const mySystemPrompt = `## ROLE: Tarot Question Linter & Moderator
## TASK: Đánh giá [CÂU HỎI] của người dùng có phù hợp để trải bài Tarot hay không và phân loại xem đó là câu hỏi bốc bài hay giao tiếp thông thường.

## QUY TẮC ĐÁNH GIÁ:
1. isValid = true, pick_card = true:
- Người dùng đặt câu hỏi rõ ràng cần bốc bài Tarot (ví dụ: "Tình cảm sắp tới của tôi ra sao?", "Tôi có nên đổi việc không?", "Cho tôi một lời khuyên").
- reason BẮT BUỘC phải là "ok".

2. isValid = true, pick_card = false:
- Người dùng chỉ đang chào hỏi hoặc cảm ơn lịch sự (ví dụ: "Chào bạn", "Cảm ơn", "Chào buổi sáng", "Ok mình hiểu rồi").
- reason phải là một câu đối đáp lịch sự (ví dụ: "Chào bạn, mình có thể giúp gì cho bạn qua các lá bài Tarot?", "Không có gì, chúc bạn một ngày tốt lành!").

3. isValid = false, pick_card = false:
- Câu hỏi quá ngắn, vô nghĩa (ví dụ: "hi", "asdasd").
- Chủ đề ngoài đời sống, vi phạm (ví dụ: giải toán, code, chửi thề).
- reason phải là một câu giải thích lịch sự lý do từ chối.

## OUTPUT FORMAT (JSON ONLY - KHÔNG bọc block code):
{"isValid": true, "pick_card": true, "reason": "ok"}`;

  const question = $('Check câu hỏi').first().json.body.question || "";

  const myUserPrompt = `### [CÂU HỎI ĐẦU VÀO CỦA KHÁCH HÀNG]\n"${question}"\n\nHãy phân tích và trả về đối tượng JSON đúng định dạng.`;

  item.json.bodyPayload = {
    model: "n8n2",
    messages: [
      { role: "system", content: mySystemPrompt },
      { role: "user", content: myUserPrompt }
    ],
    temperature: 0
  };
}

return $input.all();

const items = $input.all();
const results = [];

for (const item of items) {
  const data = item.json;
  let isValid = false;
  let pick_card = false;
  let reason = "Câu hỏi chưa rõ ràng hoặc không liên quan đến Tarot.";

  // 1. Trích xuất kết quả từ API
  let rawText = "";
  if (data.choices && data.choices[0] && data.choices[0].message) {
    rawText = data.choices[0].message.content || "";
  } else {
    rawText = data.output || data.text || "";
  }

  if (typeof rawText === 'object') {
    rawText = JSON.stringify(rawText);
  }
  rawText = rawText.trim();

  // Loại bỏ markdown code block nếu có
  if (rawText.includes('```')) {
    rawText = rawText.replace(/```json/gi, '').replace(/```/g, '').trim();
  }

  try {
    const parsed = JSON.parse(rawText);
    isValid = parsed.isValid;
    pick_card = parsed.pick_card;
    reason = parsed.reason || "ok";
  } catch (e) {
    // Fallback bằng Regex
    const lowerText = rawText.toLowerCase();
    if (lowerText.includes('"isvalid": true') || lowerText.includes('isvalid: true') || lowerText.includes('true')) {
      isValid = true;
      if (lowerText.includes('"pick_card": true') || lowerText.includes('pick_card: true')) {
          pick_card = true;
      }
      reason = "ok";
    } else {
      isValid = false;
      const match = rawText.match(/"reason"\s*:\s*"([^"]+)"/i);
      if (match && match[1]) {
        reason = match[1];
      }
    }
  }

  // 2. Ép kiểu chuẩn
  if (typeof isValid === 'string') {
    isValid = (isValid.toLowerCase() === 'true');
  } else {
    isValid = Boolean(isValid);
  }

  if (typeof pick_card === 'string') {
    pick_card = (pick_card.toLowerCase() === 'true');
  } else {
    pick_card = Boolean(pick_card);
  }

  // 3. Chuẩn hóa giá trị
  if (isValid && pick_card) {
    reason = "ok";
  } else if (!isValid && (!reason || reason === "ok" || reason === "undefined")) {
    reason = "Câu hỏi không phù hợp. Vui lòng đặt câu hỏi liên quan đến chủ đề Tarot.";
  }

  results.push({
    json: {
      output: {
        isValid: isValid,
        pick_card: pick_card,
        reason: reason
      }
    }
  });
}

return results;

for (const item of $input.all()) {
  const question = $('Luận giải tarot').first().json.body.question || "";
  const cards = item.json.cards || [];

  let isFollowUp = false;
  let previousQuestions = [];
  let historyText = "Chưa có cuộc trò chuyện nào trước đó.";

  // Lấy mảng history do Astro Webhook truyền sang
  const history = $('Luận giải tarot').first().json.body.history || [];

  if (history.length > 0) {
    isFollowUp = true;

    // Lọc ra các câu hỏi của user từ mảng history
    previousQuestions = history.filter(msg => msg.role === 'user').map(msg => msg.content);

    if (previousQuestions.length > 0) {
      const questionsStr = previousQuestions.map((q, i) => `Lần ${i+1}: "${q}"`).join('\n');
      historyText = `Các câu hỏi lữ khách đã hỏi trước đó:\n${questionsStr}`;
    }
  }

  let mySystemPrompt = "";
